class DocumentManager:
    """Handles CRUD operations for documents."""

    def __init__(self, es_client: ElasticsearchClient):
        self.es = es_client.client

    def index_document(self, index_name: str, document: Dict, doc_id: str = None) -> Dict:
        try:
            result = self.es.index(
                index=index_name,
                id=doc_id,
                body=document,
                refresh="wait_for"
            )
            logger.info(f"Document indexed in '{index_name}' with ID: {result['_id']}")
            return result
        except Exception as e:
            logger.error(f"Error indexing document: {e}")
            raise

    def bulk_index_documents(self, index_name: str, documents: List[Dict], id_field: str = None) -> Dict:
        actions = []
        for doc in documents:
            action = {
                "_index": index_name,
                "_source": doc
            }
            if id_field and id_field in doc:
                action["_id"] = doc[id_field]
            actions.append(action)

        try:
            success, errors = helpers.bulk(self.es, actions, refresh="wait_for")
            logger.info(f"Bulk indexed {success} documents into '{index_name}'")
            if errors:
                logger.warning(f"Bulk index errors: {errors}")
            return {"success": success, "errors": errors}
        except Exception as e:
            logger.error(f"Error in bulk indexing: {e}")
            raise

    def get_document(self, index_name: str, doc_id: str) -> Optional[Dict]:
        try:
            result = self.es.get(index=index_name, id=doc_id)
            return result["_source"]
        except NotFoundError:
            logger.warning(f"Document '{doc_id}' not found in '{index_name}'")
            return None

    def update_document(self, index_name: str, doc_id: str, update_fields: Dict) -> Dict:
        try:
            result = self.es.update(
                index=index_name,
                id=doc_id,
                body={"doc": update_fields},
                refresh="wait_for"
            )
            logger.info(f"Document '{doc_id}' updated in '{index_name}'")
            return result
        except NotFoundError:
            logger.error(f"Document '{doc_id}' not found for update")
            raise

    def delete_document(self, index_name: str, doc_id: str) -> bool:
        try:
            self.es.delete(index=index_name, id=doc_id, refresh="wait_for")
            logger.info(f"Document '{doc_id}' deleted from '{index_name}'")
            return True
        except NotFoundError:
            logger.warning(f"Document '{doc_id}' not found for deletion")
            return False


